rpc(DATA_ROUTE, {exclude_draft: true}).then(data => { if (data.project) map.setView([data.project.latitude || -18.8792, data.project.longitude || 47.5079], data.project.zoom || 16); (data.units || []).forEach(u => { const feature = toFeature(u.geojson); if (!feature) return; L.geoJSON(feature, {style:{color:u.color || '#6b7280', fillColor:u.color || '#6b7280', weight:2, fillOpacity:0.45}, onEachFeature:function(f, layer) { layer.bindPopup(`<b>${unitDisplayLabel(u)}</b><br/>Code : ${u.code || '-'}<br/>Statut : ${u.stage || '-'}<br/>Prix : ${u.price || 0}${priceSuffix(u)}`); layer.bindTooltip(unitDisplayLabel(u), {permanent:true, direction:'center', className:'unit-label'}); layer.on('mouseover', function() { layer.openPopup(); }); layer.on('mouseout', function() { layer.closePopup(); }); layer.on('click', function() { if (u.brocher_access_token) window.location.href = '/property-brochure/' + u.brocher_access_token; }); all.addLayer(layer); }}); }); if (all.getLayers().length) map.fitBounds(all.getBounds(), {padding:[20,20]}); });
